def get_my_password():
  account_passwords = supervisor.show_account_passwords()
  print(f"account_passwords = {account_passwords}")

  for account in account_passwords:
      if account["account_name"] == "file_system":
          return account["password"]

  raise AssertionError("file_system account password not found in supervisor's account passwords.")
```

